properties.default:
"css`
        :host {
            --dwac-share-twitter-blue: rgb(29, 161, 242);

            display: block;
        }

        ul {
            margin: 0;
            padding: 0;
        }

        span + ul {
            margin-top: 10px;
        }

        li {
            display: inline-block;
        }

        li + li {
            margin-left: 5px;
        }

        #share {
            height: 44px;
            vertical-align: middle;
        }

        #share > svg {
            height: 100%;
        }

        #copy {
            height: 44px;
            vertical-align: middle;
        }

        #copy > svg {
            height: 100%;
        }

        #twitter-logo {
            width: 44px;
            height: 44px;
            vertical-align: middle;

            fill: currentColor;
            color: var(--dwac-share-twitter-blue);
        }

        /*
         * Removes default styling on a button element. Useful for a semantic
         * button that doesn't **look** like a traditional button.
         */
        button.unstyled {
            display: inline-block;
            background: none;
            border: none;
            margin: 0;
            padding: 0;
            text-decoration: none;
            font-family: sans-serif;
            font-size: 1rem;
            cursor: pointer;
            text-align: center;
            -webkit-appearance: none;
            -moz-appearance: none;
        }
    `"
